import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(email, password);
      navigate('/dashboard');
    } catch (e: any) {
      setError(e.response?.data?.message || 'Invalid email or password');
    } finally { setLoading(false); }
  };

  const inp: React.CSSProperties = { width: '100%', padding: '10px 14px', border: '2px solid #e8e0d0', borderRadius: 10, fontSize: 14, fontFamily: 'inherit', outline: 'none', color: '#1a1a2e', background: '#fff' };

  return (
    <div style={{ minHeight: '100vh', display: 'flex' }}>
      {/* Left Panel */}
      <div style={{ width: '45%', background: '#1a1a2e', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', padding: 48 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <div style={{ width: 42, height: 42, background: '#c9a84c', borderRadius: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20 }}>📖</div>
          <span style={{ fontFamily: "'Playfair Display',serif", fontSize: 22, fontWeight: 700, color: '#fff' }}>LibraryMS</span>
        </div>
        <div>
          <p style={{ fontFamily: "'Playfair Display',serif", fontSize: 28, fontWeight: 700, color: '#fff', lineHeight: 1.3, marginBottom: 16 }}>
            "A library is not a luxury but one of the necessities of life."
          </p>
          <p style={{ color: '#c9a84c', fontSize: 13, fontWeight: 600 }}>— Henry Ward Beecher</p>
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2,1fr)', gap: 12 }}>
          {[['Librarian', '👩‍💼', 'librarian@library.com'], ['Assistant', '📋', 'assistant@library.com']].map(([label, icon, email]) => (
            <div key={label} style={{ background: 'rgba(255,255,255,0.07)', borderRadius: 12, padding: 16 }}>
              <div style={{ fontSize: 22, marginBottom: 6 }}>{icon}</div>
              <div style={{ color: '#c9a84c', fontSize: 13, fontWeight: 600 }}>{label}</div>
              <div style={{ color: 'rgba(255,255,255,0.4)', fontSize: 11, marginTop: 2 }}>{email}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Right Panel */}
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 40 }}>
        <div style={{ width: '100%', maxWidth: 400 }}>
          <h2 style={{ fontFamily: "'Playfair Display',serif", fontSize: 36, fontWeight: 700, marginBottom: 6, color: '#1a1a2e' }}>Welcome back</h2>
          <p style={{ color: '#9ca3af', fontSize: 14, marginBottom: 32 }}>Sign in to your library account</p>

          {error && <div style={{ background: '#fee2e2', color: '#dc2626', padding: '12px 16px', borderRadius: 10, fontSize: 13, marginBottom: 16 }}>{error}</div>}

          <form onSubmit={handleSubmit}>
            <div style={{ marginBottom: 16 }}>
              <label style={{ display: 'block', fontSize: 12, fontWeight: 600, color: '#6b7280', marginBottom: 6 }}>Email address</label>
              <input style={inp} type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="your@email.com" required />
            </div>
            <div style={{ marginBottom: 24 }}>
              <label style={{ display: 'block', fontSize: 12, fontWeight: 600, color: '#6b7280', marginBottom: 6 }}>Password</label>
              <input style={inp} type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" required />
            </div>
            <button type="submit" disabled={loading}
              style={{ width: '100%', padding: 12, background: '#1a1a2e', color: '#fff', border: 'none', borderRadius: 10, fontSize: 14, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit', opacity: loading ? 0.7 : 1 }}>
              {loading ? 'Signing in...' : 'Sign in →'}
            </button>
          </form>

          <div style={{ textAlign: 'center', marginTop: 20 }}>
            <p style={{ fontSize: 13, color: '#6b7280' }}>
              New student or staff?{' '}
              <Link to="/register" style={{ color: '#1a1a2e', fontWeight: 700, textDecoration: 'none' }}>Create Account</Link>
            </p>
          </div>

          <div style={{ marginTop: 20, background: '#f5f0e8', borderRadius: 10, padding: 14 }}>
            <p style={{ fontSize: 12, fontWeight: 600, marginBottom: 8, color: '#1a1a2e' }}>Staff Login (Demo)</p>
            <p style={{ fontSize: 12, color: '#6b7280' }}>Librarian: librarian@library.com</p>
            <p style={{ fontSize: 12, color: '#6b7280' }}>Assistant: assistant@library.com</p>
            <p style={{ fontSize: 12, color: '#6b7280', marginTop: 4 }}>Password: <strong>password</strong></p>
          </div>
        </div>
      </div>
    </div>
  );
}
